1	// Package delegation evaluates the ADR-040 operator_agent delegation
2	// conditions (#1026) against current run state. Each v0 knob names
3	// exactly one backend-evaluable predicate (spec.DelegationCondition);
4	// the Evaluator answers "is that predicate satisfied right now" from
5	// the same repositories the server already reads — reviewer-verdict
6	// audit entries, the durable concern store, stage rows, and the drive
7	// engine's run_auto_advanced trail — so the operator agent never
8	// re-derives a condition client-side.
9	//
10	// Fail-closed by construction: a spec with no effective operator_agent
11	// block evaluates to nil (nothing delegated), and every unmet Decision
12	// names the exact failed predicate so a refusal is explainable. The
13	// evaluator only ANSWERS conditions; enforcement at action time (the
14	// delegated approve/fixup/retry/waive paths) re-evaluates through the
15	// same code rather than trusting a client-supplied verdict.
16	package delegation
17	
18	import (
19		"context"
20		"encoding/json"
21		"fmt"
22		"strings"
23	
24		"github.com/google/uuid"
25	
26		"github.com/kuhlman-labs/fishhawk/backend/internal/audit"
27		"github.com/kuhlman-labs/fishhawk/backend/internal/concern"
28		"github.com/kuhlman-labs/fishhawk/backend/internal/drive"
29		"github.com/kuhlman-labs/fishhawk/backend/internal/planreview"
30		"github.com/kuhlman-labs/fishhawk/backend/internal/run"
31		"github.com/kuhlman-labs/fishhawk/backend/internal/spec"
32	)
33	
34	// Actions are the delegable operator verbs, one per operator_agent
35	// knob. The strings are the wire values the GET /v0/runs/{id}
36	// delegation block carries.
37	const (
38		ActionApprove    = "approve"
39		ActionRouteFixup = "route_fixup"
40		ActionWaive      = "waive"
41		ActionRetry      = "retry"
42		ActionMerge      = "merge"
43	)
44	
45	// StageLister is the slice of run.Repository the evaluator needs.
46	type StageLister interface {
47		ListStagesForRun(ctx context.Context, runID uuid.UUID) ([]*run.Stage, error)
48	}
49	
50	// ConcernLister is the slice of concern.Repository the evaluator needs.
51	type ConcernLister interface {
52		ListOpenByRun(ctx context.Context, runID uuid.UUID) ([]*concern.Concern, error)
53	}
54	
55	// AuditLister is the slice of audit.Repository the evaluator needs.
56	type AuditLister interface {
57		ListForRunByCategory(ctx context.Context, runID uuid.UUID, category string) ([]*audit.Entry, error)
58	}
59	
60	// Decision is one knob's evaluation: whether the named condition is
61	// satisfied by current run state, and — when it is not — the exact
62	// failed predicate, prefixed with the condition name (e.g.
63	// "clean_dual_approval: 1 of 2 reviewer verdicts received").
64	type Decision struct {
65		Action      string
66		Condition   spec.DelegationCondition
67		Met         bool
68		UnmetReason string
69	}
70	
71	// Result carries every configured knob's Decision plus the effective
72	// block's must_page_human event list (static configuration, surfaced
73	// alongside the evaluations so the operator agent reads its full
74	// envelope in one response).
75	type Result struct {
76		Actions       []Decision
77		MustPageHuman []string
78		// ReviewerRejectClass names the reviewer-reject page-event class the
79		// run's implement review currently resolves to (#1378): the explicit
80		// spec.PageEventGatingReviewerReject when implement review authority is
81		// gating (a reject pages the human), spec.PageEventAdvisoryReviewerReject
82		// when advisory (a reject is arbitrable / auto-routed), and "" when the
83		// implement stage is gateless (no agent-reviewer authority — omitted).
84		// This only makes the authority-resolved class legible; it does not
85		// change the page/auto decision, which stays resolved from
86		// implementReviewAuthority.
87		ReviewerRejectClass string
88	}
89	
90	// Evaluator answers delegation conditions over the server's existing
91	// repository surfaces. All three dependencies are required; the caller
92	// (handleGetRun, the delegated-action handlers) guards nil wiring and
93	// degrades by omitting the surface.
94	type Evaluator struct {
95		Stages   StageLister
96		Concerns ConcernLister
97		Audit    AuditLister
98	}
99	
100	// Configured reports whether the workflow declares an operator_agent
101	// block anywhere — workflow level or on any stage gate. A false answer
102	// lets callers skip Evaluate entirely (no repository reads), keeping
103	// unconfigured specs' responses byte-identical to today.
104	func Configured(wf *spec.Workflow) bool {
105		if wf == nil {
106			return false
107		}
108		if wf.OperatorAgent != nil {
109			return true
110		}
111		for _, st := range wf.Stages {
112			for _, g := range st.Gates {
113				if g.OperatorAgent != nil {
114					return true
115				}
116			}
117		}
118		return false
119	}
120	
121	// Evaluate resolves the effective operator_agent block for the run's
122	// current gate context and evaluates every configured knob. Returns
123	// (nil, nil) when no block governs the run — the fail-closed default:
124	// nothing is delegated and the caller omits the surface. Any
125	// repository read failure returns an error so the caller can apply its
126	// best-effort degradation (warn-log + omit), never a partial answer.
127	func (e *Evaluator) Evaluate(ctx context.Context, runRow *run.Run, wf *spec.Workflow) (*Result, error) {
128		if !Configured(wf) {
129			return nil, nil
130		}
131	
132		stages, err := e.Stages.ListStagesForRun(ctx, runRow.ID)
133		if err != nil {
134			return nil, fmt.Errorf("list stages: %w", err)
135		}
136		gated := currentGatedStage(stages)
137		effective := wf.EffectiveOperatorAgent(approvalGateForStage(wf, gated))
138		if effective == nil {
139			return nil, nil
140		}
141	
142		// A stage parked at awaiting_input (#1057) is waiting on a human to
143		// answer the planner's clarification_request — a parked D-category
144		// judgment, not a failure and not a delegable agent decision. While
145		// the run is parked for direction the operator agent must page the
146		// human rather than act, so delegate nothing: surface only the
147		// effective block's must_page_human envelope with zero met actions.
148		// This is fail-closed by intent — without it a stale open concern
149		// could still satisfy a knob (e.g. solo_low) while the run is
150		// genuinely blocked on operator answers.
151		rejectClass := reviewerRejectClass(wf)
152		if parkedAwaitingInput(stages) {
153			return &Result{MustPageHuman: effective.MustPageHuman, ReviewerRejectClass: rejectClass}, nil
154		}
155	
156		open, err := e.Concerns.ListOpenByRun(ctx, runRow.ID)
157		if err != nil {
158			return nil, fmt.Errorf("list open concerns: %w", err)
159		}
160	
161		res := &Result{MustPageHuman: effective.MustPageHuman, ReviewerRejectClass: rejectClass}
162		type knob struct {
163			action    string
164			condition spec.DelegationCondition
165			eval      func() (bool, string, error)
166		}
167		knobs := []knob{
168			{ActionApprove, effective.MayApprove, func() (bool, string, error) {
169				return e.evalCleanDualApproval(ctx, runRow, wf, gated, open)
170			}},
171			{ActionRouteFixup, effective.MayRouteFixup, func() (bool, string, error) {
172				return e.evalConvergentConcerns(ctx, runRow, wf, open)
173			}},
174			{ActionWaive, effective.MayWaive, func() (bool, string, error) {
175				return evalSoloLow(open), soloLowUnmetReason(open), nil
176			}},
177			{ActionRetry, effective.MayRetry, func() (bool, string, error) {
178				met, reason := evalInfraFlake(stages)
179				return met, reason, nil
180			}},
181			{ActionMerge, effective.MayMerge, func() (bool, string, error) {
182				return e.evalGatesResolvedCIGreen(ctx, runRow, stages, open)
183			}},
184		}
185		for _, k := range knobs {
186			if k.condition == "" {
187				continue
188			}
189			met, reason, err := k.eval()
190			if err != nil {
191				return nil, fmt.Errorf("evaluate %s: %w", k.condition, err)
192			}
193			d := Decision{Action: k.action, Condition: k.condition, Met: met}
194			if !met {
195				d.UnmetReason = reason
196			}
197			res.Actions = append(res.Actions, d)
198		}
199		return res, nil
200	}
201	
202	// parkedAwaitingInput reports whether any stage is parked at
203	// awaiting_input — the planner's clarification_request gate (#1057), a
204	// parked D-category judgment that pages the human rather than delegating.
205	func parkedAwaitingInput(stages []*run.Stage) bool {
206		for _, st := range stages {
207			if st.State == run.StageStateAwaitingInput {
208				return true
209			}
210		}
211		return false
212	}
213	
214	// currentGatedStage returns the lowest-sequence stage parked in
215	// awaiting_approval, or nil when no gate is pending.
216	func currentGatedStage(stages []*run.Stage) *run.Stage {
217		var gated *run.Stage
218		for _, st := range stages {
219			if st.State != run.StageStateAwaitingApproval {
220				continue
221			}
222			if gated == nil || st.Sequence < gated.Sequence {
223				gated = st
224			}
225		}
226		return gated
227	}
228	
229	// specStageFor finds the workflow's stage definition for a stage row,
230	// matching by spec stage ID first and falling back to type — the same
231	// two-step resolveSpecStageForRun (approvals.go) applies.
232	func specStageFor(wf *spec.Workflow, stageType run.StageType) *spec.Stage {
233		for i := range wf.Stages {
234			if wf.Stages[i].ID == string(stageType) {
235				return &wf.Stages[i]
236			}
237		}
238		for i := range wf.Stages {
239			if string(wf.Stages[i].Type) == string(stageType) {
240				return &wf.Stages[i]
241			}
242		}
243		return nil
244	}
245	
246	// approvalGateForStage returns the spec approval gate governing the
247	// gated stage row, or nil (no pending gate, stage not in spec, or no
248	// approval gate declared) — in which case the workflow-level block is
249	// the effective one.
250	func approvalGateForStage(wf *spec.Workflow, gated *run.Stage) *spec.Gate {
251		if gated == nil {
252			return nil
253		}
254		st := specStageFor(wf, gated.Type)
255		if st == nil {
256			return nil
257		}
258		for i := range st.Gates {
259			if st.Gates[i].Type == spec.GateTypeApproval {
260				return &st.Gates[i]
261			}
262		}
263		return nil
264	}
265	
266	// reviewCategories maps a stage type to its review-audit category pair.
267	// Only plan and implement stages have an agent-review surface; review
268	// stages' approval is GitHub-owned (ADR-018).
269	func reviewCategories(t run.StageType) (started, reviewed string, ok bool) {
270		switch t {
271		case run.StageTypePlan:
272			return "plan_review_started", "plan_reviewed", true
273		case run.StageTypeImplement:
274			return "implement_review_started", "implement_reviewed", true
275		}
276		return "", "", false
277	}
278	
279	// reviewRound reads the LATEST review round for a stage type: how many
280	// agents it was configured with (the *_review_started payload's
281	// configured_agents, falling back to the spec's reviewers when the
282	// entry predates #600 or is malformed) and the verdicts that landed
283	// after the round opened. Rounds are delimited by started entries —
284	// the same supersession rule the drive engine's settlement read uses,
285	// so a settled first round never satisfies a condition while a fix-up
286	// re-review is in flight.
287	func (e *Evaluator) reviewRound(ctx context.Context, runRow *run.Run, wf *spec.Workflow, stageType run.StageType) (configured int, verdicts []planreview.Verdict, started bool, err error) {
288		startedCat, reviewedCat, ok := reviewCategories(stageType)
289		if !ok {
290			return 0, nil, false, fmt.Errorf("stage type %q has no reviewer surface", stageType)
291		}
292		startedEntries, err := e.Audit.ListForRunByCategory(ctx, runRow.ID, startedCat)
293		if err != nil {
294			return 0, nil, false, fmt.Errorf("list %s: %w", startedCat, err)
295		}
296	
297		specConfigured := 0
298		if st := specStageFor(wf, stageType); st != nil && st.Reviewers != nil {
299			specConfigured = st.Reviewers.AgentCount()
300		}
301		if len(startedEntries) == 0 {
302			return specConfigured, nil, false, nil
303		}
304	
305		latest := startedEntries[0]
306		for _, en := range startedEntries {
307			if en.Sequence > latest.Sequence {
308				latest = en
309			}
310		}
311		var startedPayload planreview.ReviewStartedPayload
312		if json.Unmarshal(latest.Payload, &startedPayload) == nil {
313			configured = startedPayload.ConfiguredAgents
314		}
315		if configured == 0 {
316			configured = specConfigured
317		}
318	
319		reviewedEntries, err := e.Audit.ListForRunByCategory(ctx, runRow.ID, reviewedCat)
320		if err != nil {
321			return 0, nil, false, fmt.Errorf("list %s: %w", reviewedCat, err)
322		}
323		for _, en := range reviewedEntries {
324			if en.Sequence <= latest.Sequence {
325				continue
326			}
327			// PlanReviewedPayload and ImplementReviewedPayload share the
328			// verdict field; either decodes the slice this read needs.
329			var p planreview.ImplementReviewedPayload
330			if json.Unmarshal(en.Payload, &p) != nil || p.Verdict == "" {
331				continue
332			}
333			verdicts = append(verdicts, p.Verdict)
334		}
335		return configured, verdicts, true, nil
336	}
337	
338	// evalCleanDualApproval answers may_approve's condition: every
339	// configured reviewer for the currently gated stage returned an
340	// approve verdict and zero concerns are open. A failed or skipped
341	// review never counts as an approve — the condition requires actual
342	// clean verdicts, fail-closed.
343	func (e *Evaluator) evalCleanDualApproval(ctx context.Context, runRow *run.Run, wf *spec.Workflow, gated *run.Stage, open []*concern.Concern) (bool, string, error) {
344		const cond = string(spec.ConditionCleanDualApproval)
345		if gated == nil {
346			return false, cond + ": no stage is awaiting approval", nil
347		}
348		if _, _, ok := reviewCategories(gated.Type); !ok {
349			return false, fmt.Sprintf("%s: stage type %q has no reviewer surface (review-stage approval is GitHub-owned per ADR-018)", cond, gated.Type), nil
350		}
351		configured, verdicts, started, err := e.reviewRound(ctx, runRow, wf, gated.Type)
352		if err != nil {
353			return false, "", err
354		}
355		if configured == 0 {
356			return false, cond + ": no agent reviewers configured for the gated stage (the condition requires reviewer verdicts)", nil
357		}
358		if !started {
359			return false, fmt.Sprintf("%s: 0 of %d reviewer verdicts received (review round not dispatched)", cond, configured), nil
360		}
361		if len(verdicts) < configured {
362			return false, fmt.Sprintf("%s: %d of %d reviewer verdicts received", cond, len(verdicts), configured), nil
363		}
364		for _, v := range verdicts {
365			if v != planreview.VerdictApprove {
366				return false, fmt.Sprintf("%s: reviewer verdict %s (every verdict must be approve)", cond, v), nil
367			}
368		}
369		if n := len(open); n > 0 {
370			return false, fmt.Sprintf("%s: %d open concern(s)", cond, n), nil
371		}
372		return true, "", nil
373	}
374	
375	// implementReviewAuthority resolves the ADR-027 reviewer authority
376	// (planreview.ResolveAuthority) for the implement stage's review round:
377	// advisory when agent AND human reviewers are configured (the human
378	// approver is the authoritative gate), gating when agent-only. A stage
379	// with no Reviewers block — or absent from the spec entirely — is
380	// gateless: no agent-reviewer authority governs the verdict, so a reject
381	// can only be advisory.
382	func implementReviewAuthority(wf *spec.Workflow) planreview.AuthorityMode {
383		st := specStageFor(wf, run.StageTypeImplement)
384		if st == nil || st.Reviewers == nil {
385			return planreview.AuthorityGateless
386		}
387		return planreview.ResolveAuthority(*st.Reviewers)
388	}
389	
390	// reviewerRejectClass maps the implement-stage review authority (#1378)
391	// to the legible reviewer-reject page-event class surfaced on the wire:
392	// gating authority -> spec.PageEventGatingReviewerReject (a reject pages
393	// the human), advisory -> spec.PageEventAdvisoryReviewerReject (a reject
394	// is arbitrable / auto-routed), and gateless -> "" (no agent-reviewer
395	// authority; omitted). This is the same authority resolution the
396	// page/auto decision uses — it only makes the resolved class explicit.
397	func reviewerRejectClass(wf *spec.Workflow) string {
398		switch implementReviewAuthority(wf) {
399		case planreview.AuthorityGating:
400			return spec.PageEventGatingReviewerReject
401		case planreview.AuthorityAdvisory:
402			return spec.PageEventAdvisoryReviewerReject
403		default:
404			return ""
405		}
406	}
407	
408	// evalConvergentConcerns answers may_route_fixup's condition: the
409	// implement-review round's verdicts are all in, no GATING-authority
410	// reject is present, and at least one concern is open to route. Pinned
411	// to the implement stage because fix-up routing is an implement-stage
412	// verb.
413	//
414	// The reject branch is ADR-027 authority-aware. A planreview.VerdictReject
415	// disqualifies route_fixup and pages the human (reviewer_reject) ONLY
416	// under AuthorityGating (agent-only review). Under AuthorityAdvisory the
417	// human approver is the gate, so an agent reject is advisory and
418	// arbitrable: it does NOT disqualify, and with an open concern the
419	// condition stays met so the operator agent may auto-route the fix-up.
420	// A human reviewer reject is not an implement_reviewed verdict this
421	// evaluator reads — it arrives via plan_rejection / gate rejection, which
422	// already pages — so reviewer_reject here means a gating-authority agent
423	// reject specifically.
424	func (e *Evaluator) evalConvergentConcerns(ctx context.Context, runRow *run.Run, wf *spec.Workflow, open []*concern.Concern) (bool, string, error) {
425		const cond = string(spec.ConditionConvergentConcerns)
426		configured, verdicts, started, err := e.reviewRound(ctx, runRow, wf, run.StageTypeImplement)
427		if err != nil {
428			return false, "", err
429		}
430		if !started || configured == 0 {
431			return false, cond + ": no implement review round recorded", nil
432		}
433		if len(verdicts) < configured {
434			return false, fmt.Sprintf("%s: %d of %d reviewer verdicts received", cond, len(verdicts), configured), nil
435		}
436		gating := implementReviewAuthority(wf) == planreview.AuthorityGating
437		for _, v := range verdicts {
438			if v == planreview.VerdictReject && gating {
439				return false, cond + ": a gating-authority reviewer rejected (" + spec.PageEventGatingReviewerReject + " pages the human)", nil
440			}
441		}
442		if len(open) == 0 {
443			return false, cond + ": 0 open concerns to route", nil
444		}
445		return true, "", nil
446	}
447	
448	// evalSoloLow answers may_waive's condition: exactly one open concern
449	// and its severity is low.
450	func evalSoloLow(open []*concern.Concern) bool {
451		return len(open) == 1 && open[0].Severity == string(planreview.SeverityLow)
452	}
453	
454	// soloLowUnmetReason names the failed solo_low predicate. Empty when met.
455	func soloLowUnmetReason(open []*concern.Concern) string {
456		const cond = string(spec.ConditionSoloLow)
457		switch {
458		case evalSoloLow(open):
459			return ""
460		case len(open) != 1:
461			return fmt.Sprintf("%s: %d open concerns (the condition requires exactly one)", cond, len(open))
462		default:
463			return fmt.Sprintf("%s: the open concern's severity is %s (the condition requires low)", cond, open[0].Severity)
464		}
465	}
466	
467	// infraFlakeMarkers are the container-start markers of the
468	// testcontainers start-timeout signature (#972). The set mirrors the
469	// runner's isTestcontainersStartFlake matcher — the single emit site
470	// for the flake classification: a category-A verify failure's
471	// FailureReason embeds the verify output verbatim ("verify command %q
472	// still failing after %d iteration(s):\n<output>"), so the signature
473	// in that output IS the recorded evidence. The literal trace-event
474	// name is also accepted in case a future reason cites it directly
475	// (the posture the MCP next-actions classifier already takes).
476	var infraFlakeMarkers = []string{
477		"/var/run/docker.sock",
478		"%2Fvar%2Frun%2Fdocker.sock",
479		"failed to start container",
480		"mapped port",
481		"wait until ready",
482	}
483	
484	// hasInfraFlakeSignature reports whether a failure reason carries the
485	// infra-flake classification: the literal verify_infra_flake_retry
486	// marker, or the conservative testcontainers signature ("context
487	// deadline exceeded" AND a container-start marker — an ordinary test
488	// failure that merely mentions a deadline never matches).
489	func hasInfraFlakeSignature(reason string) bool {
490		if strings.Contains(reason, "verify_infra_flake_retry") {
491			return true
492		}
493		if !strings.Contains(reason, "context deadline exceeded") {
494			return false
495		}
496		for _, marker := range infraFlakeMarkers {
497			if strings.Contains(reason, marker) {
498				return true
499			}
500		}
501		return false
502	}
503	
504	// evalInfraFlake answers may_retry's condition: the run's latest
505	// failed stage is a category-A failure whose recorded reason carries
506	// the infra-flake signature.
507	func evalInfraFlake(stages []*run.Stage) (bool, string) {
508		const cond = string(spec.ConditionInfraFlake)
509		var failed *run.Stage
510		for _, st := range stages {
511			if st.State != run.StageStateFailed {
512				continue
513			}
514			if failed == nil || st.Sequence > failed.Sequence {
515				failed = st
516			}
517		}
518		if failed == nil {
519			return false, cond + ": no failed stage on the run"
520		}
521		if failed.FailureCategory == nil || string(*failed.FailureCategory) != "A" {
522			got := "unrecorded"
523			if failed.FailureCategory != nil {
524				got = string(*failed.FailureCategory)
525			}
526			return false, fmt.Sprintf("%s: failed stage category is %s (the condition requires a category-A failure)", cond, got)
527		}
528		if failed.FailureReason == nil || !hasInfraFlakeSignature(*failed.FailureReason) {
529			return false, cond + ": the failure reason carries no infra-flake signature"
530		}
531		return true, ""
532	}
533	
534	// evalGatesResolvedCIGreen answers may_merge's condition: the latest
535	// drive auto-advance is checks_green_awaiting_merge (review evidence
536	// terminal + required checks green, per the drive engine's stamp), the
537	// PR is open on the row, no concern is open, and no stage is parked at
538	// an approval gate. Evaluated and surfaced only — v0 has no backend
539	// merge endpoint to enforce it on; enforcement attaches when a merge
540	// action surface exists.
541	func (e *Evaluator) evalGatesResolvedCIGreen(ctx context.Context, runRow *run.Run, stages []*run.Stage, open []*concern.Concern) (bool, string, error) {
542		const cond = string(spec.ConditionGatesResolvedCIGreen)
543		entries, err := e.Audit.ListForRunByCategory(ctx, runRow.ID, drive.Category)
544		if err != nil {
545			return false, "", fmt.Errorf("list %s: %w", drive.Category, err)
546		}
547		var latest *audit.Entry
548		for _, en := range entries {
549			if latest == nil || en.Sequence > latest.Sequence {
550				latest = en
551			}
552		}
553		if latest == nil {
554			return false, cond + ": no checks_green_awaiting_merge auto-advance recorded", nil
555		}
556		var adv drive.Advance
557		if json.Unmarshal(latest.Payload, &adv) != nil || adv.Rule != drive.RuleChecksGreenAwaitingMerge {
558			return false, cond + ": the latest auto-advance is not checks_green_awaiting_merge", nil
559		}
560		if runRow.PullRequestURL == nil || *runRow.PullRequestURL == "" {
561			return false, cond + ": no pull request recorded on the run", nil
562		}
563		if gated := currentGatedStage(stages); gated != nil {
564			return false, fmt.Sprintf("%s: the %s stage is still awaiting approval", cond, gated.Type), nil
565		}
566		if n := len(open); n > 0 {
567			return false, fmt.Sprintf("%s: %d open concern(s)", cond, n), nil
568		}
569		return true, "", nil
570	}
571

