{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://fishhawk.dev/spec/workflow-v1.schema.json",
  "title": "Fishhawk workflow spec v1",
  "description": "Schema for .fishhawk/workflows.yaml at major version 1. v1 began as a structural copy of workflow-v0 (ADR-046 / #1380) and now adds the deploy surface (E23.2 / #1382, per ADR-038 / #925): the `deploy` stage type, the `deployment` produces artifact, the delegating executor (executor.delegate -> github_actions workflow_ref / webhook url), and the three pre-flight deploy constraint kinds (allowed_environments, change_freeze, required_upstream). Deploy is delegating-only \u2014 Fishhawk holds no deploy logic or credentials. v0 stays frozen and rejects `deploy` via its closed enums; the type<->executor<->constraint binding is enforced semantically by the version-agnostic validator. The version-routed validator dispatches on the version major (0.x -> this schema's sibling workflow-v0; 1.x -> this schema). Never break a published schema in place \u2014 bump the major instead.",
  "type": "object",
  "additionalProperties": false,
  "required": [
    "version",
    "workflows"
  ],
  "properties": {
    "version": {
      "type": "string",
      "enum": [
        "1.0"
      ],
      "description": "Spec syntax version. workflow-v1 currently advertises exactly 1.0, a structural copy of the latest workflow-v0 grammar (no deploy content yet; deferred to E23.2). The validator routes a spec to this schema when its version major is 1. Old specs in the audit log remain readable forever via their historical schemas; this enum gates *new* v1 specs only."
    },
    "roles": {
      "type": "object",
      "description": "Named roles referenced by gate approvers. Keys are snake_case identifiers; values list GitHub user/team refs.",
      "additionalProperties": false,
      "patternProperties": {
        "^[a-z][a-z0-9_]*$": {
          "$ref": "#/$defs/role"
        }
      }
    },
    "workflows": {
      "type": "object",
      "description": "Named workflows. Keys are snake_case identifiers (e.g. feature_change). At least one workflow must be defined.",
      "minProperties": 1,
      "additionalProperties": false,
      "patternProperties": {
        "^[a-z][a-z0-9_]*$": {
          "$ref": "#/$defs/workflow"
        }
      }
    },
    "test_conventions": {
      "type": "array",
      "description": "Optional per-repo test-location conventions that generalize the plan-gate test sweep (#1004) beyond the built-in Go (name.go -> name_test.go) and colocated-TypeScript defaults. Each entry maps production files matching a glob to candidate test-file path templates. Declared entries are ADDITIVE to the built-in defaults (Go + colocated TS stay covered regardless), so a repo typically declares only its Python / Ruby / parallel-tree conventions. Advisory-only and fail-open: the sweep never blocks a plan. Additive optional field within workflow-v0.x \u2014 accepted at every advertised version.",
      "items": {
        "$ref": "#/$defs/test_convention"
      }
    }
  },
  "$defs": {
    "test_convention": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "match",
        "candidates"
      ],
      "description": "One test-location convention: a production file whose repo-relative path matches `match` is expected to have a test at one of `candidates`. The plan-gate test sweep (#1004) flags an existing candidate test that is absent from the plan's scope.files.",
      "properties": {
        "match": {
          "type": "string",
          "minLength": 1,
          "description": "Doublestar glob (bmatcuk/doublestar/v4 semantics; `**` crosses directory separators) matched against the repo-relative production-file path, e.g. `**/*.go`, `**/*.{ts,tsx}`, `src/**/*.py`. A scoped file whose basename also matches a candidate's test-file shape is treated as a test, not a production file."
        },
        "candidates": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "string",
            "minLength": 1
          },
          "description": "Candidate test-file path templates for a matched production file. Template variables: `{dir}` (the production file's directory), `{name}` (basename without its final extension), `{ext}` (final extension without the leading dot), `{relpath}` (full repo-relative path without its final extension). Examples: `{dir}/{name}_test.go`, `tests/test_{name}.py`, `spec/{relpath}_spec.rb`. The sweep reports a candidate that exists on the base ref but is missing from scope.files."
        }
      }
    },
    "role": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "members"
      ],
      "properties": {
        "members": {
          "type": "array",
          "minItems": 1,
          "items": {
            "$ref": "#/$defs/member-ref"
          }
        }
      }
    },
    "member-ref": {
      "type": "string",
      "pattern": "^@[A-Za-z0-9._-]+(?:/[A-Za-z0-9._-]+)?$",
      "description": "GitHub user (@user) or team (@org/team) reference. Resolved against the GitHub App installation at run time."
    },
    "workflow": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "stages"
      ],
      "properties": {
        "description": {
          "type": "string"
        },
        "stages": {
          "type": "array",
          "minItems": 1,
          "items": {
            "$ref": "#/$defs/stage"
          }
        },
        "on_ci_failure": {
          "$ref": "#/$defs/on_ci_failure"
        },
        "policy": {
          "$ref": "#/$defs/policy"
        },
        "drive": {
          "type": "boolean",
          "description": "Opt-in drive mode (#1023 / #996 theme 1): when true, fishhawkd auto-advances the run's mechanical transitions (plan-approved dispatch, review-verdict settlement, fixup re-park, checks-green awaiting_merge) and records a run_auto_advanced audit entry per advance. Judgment points (gate approvals, concern routing, merge) always park. Default false preserves operator-driven advancement. Overridable per-run via POST /v0/runs `drive`. Additive within workflow-v0.x."
        },
        "budgets": {
          "type": "array",
          "description": "Periodic per-workflow cost ceilings (ADR-030 / #688). Each entry caps total USD spend across all runs of this workflow within a calendar period, resetting at the period boundary. Distinct from the per-stage `budget` ($defs/budget: token/runtime caps on one stage execution). Requires version 0.4+.",
          "items": {
            "$ref": "#/$defs/periodic_budget"
          }
        },
        "operator_agent": {
          "$ref": "#/$defs/operator_agent"
        },
        "decomposition": {
          "$ref": "#/$defs/decomposition"
        }
      }
    },
    "decomposition": {
      "type": "object",
      "additionalProperties": false,
      "description": "Per-workflow decomposition controls (E24.6 / #1146). Requires version 0.6+.",
      "properties": {
        "max_parallel": {
          "type": "integer",
          "minimum": 0,
          "description": "Maximum number of decomposed child runs that may dispatch concurrently for a run of this workflow. 0 = unlimited. Per-workflow override of the global FISHHAWKD_MAX_PARALLEL_CHILDREN; when > 0 it wins, otherwise the global default applies. This declares the cap; concurrency throttling that consumes it lands in E24.3 (#1143)."
        }
      }
    },
    "policy": {
      "type": "object",
      "additionalProperties": false,
      "description": "Per-workflow execution policy.",
      "properties": {
        "max_stage_runtime": {
          "type": "string",
          "pattern": "^([0-9]+(ns|us|ms|s|m|h))+$",
          "description": "Default wall-clock cap for every agent stage in the workflow. Overridable per-stage via executor.timeout. Parsed by time.ParseDuration. Resolved by spec.ResolveStageTimeout on the backend and delivered to the runner via agent_timeout_seconds on the prompt-fetch response."
        }
      }
    },
    "on_ci_failure": {
      "type": "object",
      "additionalProperties": false,
      "description": "Auto-retry policy when a required CI check fails on the implement stage's PR (#276 / E16). The dispatcher fires a fresh implement workflow_dispatch up to `max_retries` times, threading the new run via `parent_run_id` (#216). Only the closed set of failing conclusions in stagecheck.DeriveState triggers a retry; `fishhawk_audit_complete` failures are explicitly excluded \u2014 retrying won't fix Fishhawk's own audit gaps.",
      "properties": {
        "max_retries": {
          "type": "integer",
          "minimum": 0,
          "maximum": 5,
          "description": "Bound on the retry chain length. 1 (the default when the field is absent) means \"on CI failure, dispatch one more run, total agent-touch count 2.\" 0 disables auto-retries \u2014 useful for low-autonomy workflows that prefer a human re-trigger. Capped at 5 to keep runaway loops contained in v0."
        }
      }
    },
    "stage": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "id",
        "type",
        "executor"
      ],
      "properties": {
        "id": {
          "type": "string",
          "pattern": "^[a-z][a-z0-9_]*$",
          "description": "Unique within the parent workflow. Referenced by inputs.from_stage."
        },
        "type": {
          "type": "string",
          "enum": [
            "plan",
            "implement",
            "review",
            "deploy"
          ],
          "description": "Closed set. plan/implement/review are inherited from v0; deploy is the v1 delegating release stage (ADR-038 / #925). A deploy stage holds no deploy logic or credentials in Fishhawk — it delegates execution to an external pipeline via a delegating executor (executor.delegate) and gates on pre-flight constraints. The type<->executor<->constraint binding is enforced semantically by the validator. Custom stage types remain disallowed."
        },
        "executor": {
          "$ref": "#/$defs/executor"
        },
        "inputs": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/input"
          }
        },
        "produces": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/produces"
          }
        },
        "constraints": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/constraint"
          }
        },
        "budget": {
          "$ref": "#/$defs/budget"
        },
        "gates": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/gate"
          }
        },
        "reviewers": {
          "$ref": "#/$defs/reviewers_config"
        }
      }
    },
    "executor": {
      "type": "object",
      "description": "Exactly one of agent (string), human (true), or delegate (an external pipeline). The delegate branch is the v1 delegating executor (ADR-038 / #925) and is valid ONLY on a deploy stage; agent/human are valid only on non-deploy stages. The type<->executor binding is enforced semantically by the validator.",
      "unevaluatedProperties": false,
      "oneOf": [
        {
          "required": [
            "agent"
          ],
          "properties": {
            "agent": {
              "type": "string",
              "minLength": 1,
              "description": "Agent identifier. v0 ships claude-code (default) and codex (the OpenAI Codex CLI); v0.x later adds cursor and copilot. The runner resolves this free-form string to a coding-agent adapter \u2014 see runner/README.md 'Choosing the coding agent' for provider setup (the OPENAI_API_KEY secret for codex)."
            },
            "model": {
              "type": "string",
              "minLength": 1,
              "description": "Optional model override for this stage's agent invocation (#1013). One rung of the implement-model resolution ladder: deployment default < this executor.model < plan model_recommendation < operator gate decision. Empty/absent falls through to the next-lower rung (ultimately the deployment default spawn). The resolved model is validated against the deployment's per-adapter allowed-model set at the approval gate. Additive optional field within workflow-v0.x \u2014 accepted at every advertised version."
            },
            "timeout": {
              "type": "string",
              "pattern": "^([0-9]+(ns|us|ms|s|m|h))+$",
              "description": "Wall-clock cap for this stage's agent invocation. Overrides workflow.policy.max_stage_runtime when set. Falls back to the workflow policy or the backend default (15m) when absent. Parsed by time.ParseDuration."
            },
            "verify": {
              "type": "object",
              "additionalProperties": false,
              "required": [
                "command"
              ],
              "description": "Optional in-band test gate. When present, the runner executes the command after the agent exits cleanly. Non-zero exit demotes the run to category-A before the bundle is committed.",
              "properties": {
                "command": {
                  "type": "string",
                  "minLength": 1,
                  "description": "Shell command run as the verify gate (executed via sh -c). Non-zero exit code demotes the run to category-A."
                },
                "timeout": {
                  "type": "string",
                  "pattern": "^([0-9]+(ns|us|ms|s|m|h))+$",
                  "description": "Wall-clock cap on the verify command. Parsed by time.ParseDuration. Defaults to 10m when absent."
                },
                "max_iterations": {
                  "type": "integer",
                  "minimum": 0,
                  "default": 0,
                  "description": "0 (default) preserves today's single-shot demote-on-failure verify gate; >0 enables a bounded evaluator-optimizer fix loop run against the committed scope-only tree, capping the TOTAL verify-fix agent invocations across the stage at this value. Worst-case wall clock is bounded by (max_iterations+1) x executor.timeout plus (max_iterations+1) x verify.timeout; max_iterations is the control surface and ties to the periodic cost budget (ADR-030)."
                }
              }
            },
            "agent_self_retry": {
              "type": "boolean",
              "description": "Opt-in flag (default false, per ADR-023) that tells the runner to allow the agent one self-initiated retry when it detects a recoverable failure before yielding to the workflow's on_ci_failure policy. Only meaningful on agent-executed stages; setting it on a human executor is a schema error (the field is declared in the agent branch only, so unevaluatedProperties rejects it on the human branch)."
            }
          }
        },
        {
          "required": [
            "human"
          ],
          "properties": {
            "human": {
              "type": "boolean",
              "const": true
            }
          }
        },
        {
          "required": [
            "delegate"
          ],
          "properties": {
            "delegate": {
              "type": "object",
              "description": "Delegating-executor declaration for a deploy stage (ADR-038 / #925). Fishhawk holds no deploy logic or credentials; a deploy stage delegates execution to the external pipeline named here. Valid ONLY on a deploy stage (the type<->executor binding is enforced semantically by the validator). The target discriminator selects the pipeline kind.",
              "unevaluatedProperties": false,
              "oneOf": [
                {
                  "description": "Dispatch a GitHub Actions workflow via workflow_dispatch.",
                  "required": [
                    "target",
                    "workflow_ref"
                  ],
                  "properties": {
                    "target": {
                      "const": "github_actions"
                    },
                    "workflow_ref": {
                      "type": "string",
                      "minLength": 1,
                      "description": "The workflow_dispatch workflow file or id to dispatch (e.g. `deploy.yml` or a numeric workflow id)."
                    },
                    "git_ref": {
                      "type": "string",
                      "minLength": 1,
                      "description": "Optional branch/tag/sha to dispatch the workflow against. Absent = the provider's default ref."
                    }
                  }
                },
                {
                  "description": "POST the deploy trigger to a generic webhook.",
                  "required": [
                    "target",
                    "url"
                  ],
                  "properties": {
                    "target": {
                      "const": "webhook"
                    },
                    "url": {
                      "type": "string",
                      "minLength": 1,
                      "description": "The webhook endpoint the deploy trigger is POSTed to."
                    }
                  }
                }
              ]
            }
          }
        }
      ]
    },
    "input": {
      "type": "object",
      "unevaluatedProperties": false,
      "oneOf": [
        {
          "description": "Trigger input from outside the workflow (an issue, a PR).",
          "required": [
            "source"
          ],
          "properties": {
            "source": {
              "type": "string",
              "enum": [
                "github_issue",
                "pull_request"
              ]
            },
            "required": {
              "type": "boolean"
            }
          }
        },
        {
          "description": "Artifact input from a prior stage in the same run.",
          "required": [
            "artifact",
