      ]
    },
    "produces": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "artifact"
      ],
      "properties": {
        "artifact": {
          "type": "string",
          "enum": [
            "plan",
            "pull_request",
            "deployment"
          ],
          "description": "Closed set. plan/pull_request are inherited from v0; deployment is the v1 runtime artifact a deploy stage emits (ADR-038 / #925) capturing the delegated release outcome {environment, ref/sha, external_run_url, outcome, rollback_handle}. The deployment artifact is valid ONLY on a deploy stage (enforced semantically by the validator). Custom artifacts remain deferred."
        },
        "schema": {
          "type": "string",
