      ],
      "properties": {
        "target": {
          "type": "string",
          "enum": [
            "originating_issue",
            "fishhawk_audit_log"
          ]
        },
        "mode": {
          "type": "string",
          "enum": [
            "rendered_comment",
            "canonical"
          ],
          "description": "rendered_comment: posted as a formatted comment on the target. canonical: stored as the authoritative copy in the audit log."
        },
        "update_on_change": {
          "type": "boolean",
          "description": "Re-publish to the target if the artifact is regenerated."
        }
      }
    },
    "constraint": {
      "type": "object",
      "description": "Exactly one constraint kind per object. Two families: the post-hoc diff constraints (max_files_changed, forbidden_paths, allowed_paths, required_outcomes) evaluated against a stage's produced diff \u2014 closed set per MVP_SPEC \u00a74.1, valid on non-deploy stages \u2014 and the v1 PRE-FLIGHT deploy constraints (allowed_environments, change_freeze, required_upstream; ADR-038 / #925) evaluated BEFORE a delegating deploy stage executes. ADR-038 makes the post-hoc diff constraints meaningless for a delegating deploy and the pre-flight kinds meaningless off a deploy stage; the type<->constraint binding is enforced semantically by the validator.",
      "additionalProperties": false,
      "minProperties": 1,
      "maxProperties": 1,
      "properties": {
        "max_files_changed": {
          "type": "integer",
          "minimum": 1
        },
        "forbidden_paths": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "string",
            "minLength": 1
          },
          "description": "Glob patterns (gitignore-style) that the stage's diff must not touch."
        },
        "allowed_paths": {
          "type": "array",
          "minItems": 1,
          "items": {
            "type": "string",
            "minLength": 1
          },
          "description": "Glob patterns; the stage's diff must touch only these paths."
        },
        "required_outcomes": {
          "type": "array",
          "minItems": 1,
          "uniqueItems": true,
