          "minItems": 1,
          "items": {
            "type": "string",
            "minLength": 1
          },
          "description": "PRE-FLIGHT deploy constraint (evaluated BEFORE execution; ADR-038 / #925). The deploy stage may target only these environments. Distinct from the post-hoc diff constraints, which are meaningless for a delegating deploy; valid only on a deploy stage."
        },
        "change_freeze": {
          "type": "boolean",
          "description": "PRE-FLIGHT deploy constraint (evaluated BEFORE execution; ADR-038 / #925). When true the deploy stage is blocked while a change freeze is active. The freeze-signal source is out of scope for the spec (it belongs to the run lifecycle / runner that consume the spec); this declares the gate. Valid only on a deploy stage."
        },
        "required_upstream": {
          "type": "array",
          "minItems": 1,
          "uniqueItems": true,
          "items": {
            "type": "string",
            "enum": [
              "review_merged",
              "ci_green"
            ]
          },
          "description": "PRE-FLIGHT deploy constraint (evaluated BEFORE execution; ADR-038 / #925). Upstream conditions that must hold before the deploy stage is allowed to run. Valid only on a deploy stage."
        }
