    "budget": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "max_tokens": {
          "type": "integer",
          "minimum": 1
        },
        "max_runtime_minutes": {
          "type": "integer",
          "minimum": 1
        },
        "enforcement": {
          "type": "string",
          "enum": [
            "advisory",
            "blocking"
          ],
