			stages: planGated,
			audit: &fakeAudit{entries: map[string][]*audit.Entry{
				"plan_review_started": {startedEntry(1, 2)},
				"plan_reviewed": {
					verdictEntry(2, planreview.VerdictApprove),
					verdictEntry(3, planreview.VerdictApproveWithConcerns),
